"use client";

import { useMemo, useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { BridgePrimaryButton } from "@/features/bridge/components/BridgePrimaryButton";
import { useBridge } from "@/features/bridge/hooks/use-bridge";
import {
  RETURNS,
  STATUS_LABEL,
  RECOVERY_LABEL,
  actionForReturn,
  ACTION_LABEL_PANEL,
  returnsAI,
  type ReturnRow,
  type ReturnStatus,
} from "@/features/ops/api/ops-returns-data";
import "./returns.css";

const fmtUSD = (v: number) => `$${Math.round(v).toLocaleString()}`;

type Filter = "all" | ReturnStatus | "week";
const FILTER_KEYS: Filter[] = ["pending", "week", "resolved", "all"];
const FILTER_LABELS = ["Pending", "This week", "Resolved", "All"];

const WEEK_DATES = new Set(["May 18", "May 17", "May 16", "May 15", "May 14"]);

const FILTER_FN: Record<Filter, (r: ReturnRow) => boolean> = {
  pending: (r) => r.status === "pending",
  week: (r) => WEEK_DATES.has(r.date),
  resolved: (r) => r.status === "resolved",
  approved: (r) => r.status === "approved",
  all: () => true,
};

type SortKey = "id" | "customer" | "reason" | "trueCost" | "recSort" | "statusSort";

const COLS: Array<{ k: SortKey; l: string; num?: boolean }> = [
  { k: "id", l: "Return" },
  { k: "customer", l: "Customer" },
  { k: "reason", l: "Reason" },
  { k: "trueCost", l: "True cost", num: true },
  { k: "recSort", l: "Recovery" },
  { k: "statusSort", l: "Status" },
];

const ArrowSvg = () => (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <line x1="5" y1="12" x2="19" y2="12" />
    <polyline points="12 5 19 12 12 19" />
  </svg>
);

export default function ReturnsPage() {
  const [filterIdx, setFilterIdx] = useState(0);
  const filter: Filter = FILTER_KEYS[filterIdx];

  const [sortKey, setSortKey] = useState<SortKey>("statusSort");
  const [sortDir, setSortDir] = useState<1 | -1>(1);
  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [rowActionSent, setRowActionSent] = useState<number | null>(null);
  const [panelBridgeSent, setPanelBridgeSent] = useState(false);
  const [patternSent, setPatternSent] = useState(false);

  const visible = useMemo(() => {
    const fn = FILTER_FN[filter];
    const arr = RETURNS.filter(fn).slice();
    arr.sort((a, b) => {
      if (sortKey === "id" || sortKey === "customer" || sortKey === "reason") {
        return String(a[sortKey]).localeCompare(String(b[sortKey])) * sortDir;
      }
      return (((a[sortKey] as unknown as number) || 0) - ((b[sortKey] as unknown as number) || 0)) * sortDir;
    });
    return arr;
  }, [filter, sortKey, sortDir]);

  const selected: ReturnRow | null = selectedIdx != null ? RETURNS[selectedIdx] : null;

  const onSelect = (i: number) => {
    setSelectedIdx((cur) => (cur === i ? null : i));
    setPanelBridgeSent(false);
  };
  const handleSort = (k: SortKey) => {
    if (sortKey === k) setSortDir((d) => (d === 1 ? -1 : 1));
    else {
      setSortKey(k);
      setSortDir(1);
    }
  };
  const { openBridge } = useBridge();
  /** Per execution map §11 Returns: triage + refund go to `return`,
   *  packaging/courier pattern → `packaging-review`. */
  const sendRowAction = (i: number) => {
    setRowActionSent(i);
    openBridge("ops", "return");
    setTimeout(() => setRowActionSent(null), 1400);
  };
  const sendPanelBridge = () => {
    setPanelBridgeSent(true);
    openBridge("ops", "return");
    setTimeout(() => setPanelBridgeSent(false), 1700);
  };
  const sendPattern = () => {
    setPatternSent(true);
    openBridge("ops", "packaging-review");
    setTimeout(() => setPatternSent(false), 1800);
  };

  const recBodyHtml = (r: ReturnRow) => {
    if (r.recovery === "restock")
      return `Inspected and resellable — <strong>${fmtUSD(r.refund)}</strong> of stock returns to inventory. Only the $${r.delivery} return shipping is unrecoverable.`;
    if (r.recovery === "partial")
      return `Part resellable after light rework; <strong>${fmtUSD(r.waste)}</strong> written off. Net recovery roughly ${fmtUSD(r.refund - r.waste)}.`;
    return `Damaged beyond resale — <strong>${fmtUSD(r.refund + r.waste)}</strong> lost in full. This is where damaged-in-transit hurts most.`;
  };
  const RECOVERY_HEAD: Record<string, string> = {
    restock: "Fully restockable",
    partial: "Partially restockable",
    lost: "Lost to waste",
  };

  return (
    <div className="ops-returns-page">
      <DeptHeader
        dept="ops"
        title="Returns"
        meta={<><span className="live">Live</span> · What returns really cost — and the pattern driving them</>}
        actions={
          <>
            <button className="btn-util">Export</button>
            <BridgePrimaryButton dept="ops" page="return">Process approved → Bridge</BridgePrimaryButton>
          </>
        }
      />

      <PeriodTabs labels={FILTER_LABELS} activeIndex={filterIdx} onChange={setFilterIdx} />

      {/* ───── KPIs ───── */}
      <div className="ret-kpis">
        <div className="ret-kpi">
          <div className="lbl">Pending review</div>
          <div className="val amber">{RETURNS.filter((r) => r.status === "pending").length}</div>
          <div className="sub">awaiting triage</div>
        </div>
        <div className="ret-kpi">
          <div className="lbl">This week</div>
          <div className="val">12</div>
          <div className="sub">$14,200 in refunds</div>
        </div>
        <div className="ret-kpi">
          <div className="lbl">Refunds issued · 30d</div>
          <div className="val">$18,400</div>
          <div className="sub">25 of 892 orders</div>
        </div>
        <div className="ret-kpi">
          <div className="lbl">Return rate · 30d</div>
          <div className="val green">2.8%</div>
          <div className="sub ok">below 3% benchmark</div>
        </div>
      </div>

      {/* ───── True cost + recovery hero ───── */}
      <div className="ret-hero">
        <div className="rh-cost">
          <div className="rh-eyebrow">True cost of returns · last 30 days</div>
          <div className="rh-big">$28,200</div>
          <div className="rh-over">53% more than the refund alone</div>
          <div className="rh-stack">
            <div className="rh-seg refund" style={{ width: "65%" }}>
              <span className="sl">Refund $18,400</span>
            </div>
            <div className="rh-seg delivery" style={{ width: "18%" }}>
              <span className="sl">$5,000</span>
            </div>
            <div className="rh-seg waste" style={{ width: "17%" }}>
              <span className="sl">$4,800</span>
            </div>
          </div>
          <div className="rh-legend">
            <span className="rh-li"><i className="refund" />Refund <b>$18,400</b></span>
            <span className="rh-li"><i className="delivery" />Return delivery <b>$5,000</b></span>
            <span className="rh-li"><i className="waste" />Waste &amp; labor <b>$4,800</b></span>
          </div>
        </div>
        <div className="rh-recovery">
          <div className="rh-rec-h">Recovery · what comes back as stock</div>
          <div className="rh-rec-bar">
            <span className="restock" style={{ width: "62%" }}>62% restockable</span>
            <span className="lost" style={{ width: "38%" }}>38% lost</span>
          </div>
          <div className="rh-rec-note">
            <strong>$11,400</strong> of returned goods recovers as resellable stock; <strong>$7,000</strong> is lost to damage and waste. Lifting restock rate is the fastest way to shrink the true cost.
          </div>
        </div>
      </div>

      {/* ───── Pattern callout ───── */}
      <div className="ret-pattern">
        <div className="rp-icon">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.9">
            <path d="M12 2L2 19h20z" />
            <path d="M12 9v5M12 17h.01" />
          </svg>
        </div>
        <div className="rp-body">
          <div className="rp-h">Damaged-in-transit is up 40% this month — now the top return reason</div>
          <div className="rp-sub">
            9 of 25 returns · concentrated on fragile items shipped via one courier. A pattern, not noise.
          </div>
        </div>
        <button
          className={`rp-action${patternSent ? " sent" : ""}`}
          onClick={sendPattern}
        >
          {patternSent ? "Sent to Bridge ✓" : "Review packaging & courier →"}
        </button>
      </div>

      {/* ───── AI strip ───── */}
      <AIStrip label={returnsAI.label} meta={returnsAI.meta} cards={returnsAI.cards} />

      {/* ───── Returns ledger + slide-in ───── */}
      <div className="ret-section-label">
        Returns
        <span className="count">
          {visible.length === RETURNS.length
            ? `most recent ${RETURNS.length} returns · newest first`
            : `${visible.length} of ${RETURNS.length} shown`}
        </span>
      </div>

      <div className={`led-split${selected ? " open" : ""}`}>
        <div className="led-main">
          <div className="ret-ledger">
            <div className="ret-head">
              {COLS.map((c) => {
                const active = sortKey === c.k;
                return (
                  <div
                    key={c.k}
                    className={`th${active ? " active" : ""}`}
                    onClick={() => handleSort(c.k)}
                  >
                    {c.l}
                    <span className="ar">{active ? (sortDir > 0 ? "▲" : "▼") : "▲"}</span>
                  </div>
                );
              })}
            </div>

            {visible.length === 0 ? (
              <div className="ret-empty">No returns in this view</div>
            ) : (
              visible.map((r) => {
                const act = actionForReturn(r);
                return (
                  <div
                    key={r.id}
                    className={`ret-row${selectedIdx === r.idx ? " sel" : ""}`}
                    onClick={() => onSelect(r.idx)}
                  >
                    <span className="rt-id">{r.id}</span>
                    <span>
                      <span className="rt-cust">{r.customer}</span>
                      <span className="rt-order">{r.order}</span>
                    </span>
                    <span className={`rt-reason${r.flag ? " flag" : ""}`}>{r.reason}</span>
                    <span className="rt-refund">
                      {fmtUSD(r.trueCost)}
                      <span className="rt-refund-sub">{fmtUSD(r.refund)} refund</span>
                    </span>
                    <span>
                      <span className={`rt-rec ${r.recovery}`}>{RECOVERY_LABEL[r.recovery]}</span>
                    </span>
                    <span>
                      <span className={`rt-pill ${r.status}`}>{STATUS_LABEL[r.status]}</span>
                    </span>
                    <button
                      className={`ret-act${act.kind === "view" ? " view" : ""}${rowActionSent === r.idx ? " sent" : ""}`}
                      onClick={(e) => {
                        e.stopPropagation();
                        sendRowAction(r.idx);
                      }}
                    >
                      {rowActionSent === r.idx ? `${act.label} ✓` : (
                        <>
                          {act.label}
                          <ArrowSvg />
                        </>
                      )}
                    </button>
                  </div>
                );
              })
            )}
          </div>
        </div>

        {/* ───── Slide-in: true cost + cross-room signals ───── */}
        <aside className="led-detail">
          <div className="led-detail-in">
            {!selected ? (
              <div className="td-empty">
                <div className="ttl">Return detail</div>
                <div className="lead">
                  Click a return to see its true cost beyond the refund, what recovers as stock, and the cross-room signals it sends — churn risk, margin hit, and restock recovery.
                </div>
              </div>
            ) : (
              <>
                <div className="td-head">
                  <div>
                    <div className="td-id">{selected.id} · {selected.order}</div>
                    <div className="td-cust">{selected.customer}</div>
                    <div className="td-meta">
                      {selected.item} · {selected.reason}
                    </div>
                  </div>
                  <button className="td-clear" onClick={() => setSelectedIdx(null)}>
                    clear ✕
                  </button>
                </div>

                <div className="td-section">True cost of this return</div>
                <div className="td-cost">
                  <span className="cn"><i style={{ background: "#cf4444" }} />Refund</span>
                  <span className="cv">{fmtUSD(selected.refund)}</span>
                </div>
                <div className="td-cost">
                  <span className="cn"><i style={{ background: "#d98a4a" }} />Return delivery</span>
                  <span className="cv">{fmtUSD(selected.delivery)}</span>
                </div>
                <div className="td-cost">
                  <span className="cn"><i style={{ background: "#b88a2a" }} />Waste &amp; labor</span>
                  <span className="cv">{fmtUSD(selected.waste)}</span>
                </div>
                <div className="td-cost total">
                  <span className="cn">True cost</span>
                  <span className="cv">{fmtUSD(selected.trueCost)}</span>
                </div>

                <div className={`td-rec ${selected.recovery}`}>
                  <div className="rl">{RECOVERY_HEAD[selected.recovery]}</div>
                  <div className="rb" dangerouslySetInnerHTML={{ __html: recBodyHtml(selected) }} />
                </div>

                <div className="td-section">Cross-room signals</div>
                {selected.flag && (
                  <div className="td-signal">
                    <div className="td-sig-icon cust">
                      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8">
                        <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2" />
                        <circle cx="9" cy="7" r="4" />
                      </svg>
                    </div>
                    <div className="td-sig-body">
                      <div className="td-sig-room">→ Customers · churn signal</div>
                      <div className="td-sig-txt">
                        <strong>{selected.customer}</strong> received a damaged item — a leading churn indicator. Flag for a recovery touch before they lapse.
                      </div>
                    </div>
                    <span className="td-sig-go">›</span>
                  </div>
                )}
                <div className="td-signal">
                  <div className="td-sig-icon fin">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8">
                      <path d="M4 19h16M7 16V9M12 16V5M17 16v-4" />
                    </svg>
                  </div>
                  <div className="td-sig-body">
                    <div className="td-sig-room">→ Finance · margin (CM2)</div>
                    <div className="td-sig-txt">
                      True cost <strong>{fmtUSD(selected.trueCost)}</strong> hits CM2 — refund plus {fmtUSD(selected.delivery + selected.waste)} of reship and waste the P&amp;L must absorb.
                    </div>
                  </div>
                  <span className="td-sig-go">›</span>
                </div>
                {selected.recovery !== "lost" && (
                  <div
                    className="td-signal"
                    onClick={() => {
                      window.location.href = "/ops/inventory";
                    }}
                  >
                    <div className="td-sig-icon inv">
                      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8">
                        <path d="M3 7l9-4 9 4-9 4-9-4z" />
                        <path d="M3 7v10l9 4 9-4V7" />
                      </svg>
                    </div>
                    <div className="td-sig-body">
                      <div className="td-sig-room">→ Inventory · restock recovery</div>
                      <div className="td-sig-txt">
                        <strong>{selected.item}</strong> returns to sellable stock on approval — recovers {selected.recovery === "partial" ? "part of " : ""}the unit cost.
                      </div>
                    </div>
                    <span className="td-sig-go">›</span>
                  </div>
                )}

                {(() => {
                  const act = actionForReturn(selected);
                  const label = ACTION_LABEL_PANEL[act.kind];
                  return (
                    <button
                      className={`td-bridge${panelBridgeSent ? " sent" : ""}`}
                      onClick={sendPanelBridge}
                    >
                      {panelBridgeSent ? label.replace("→ Bridge", "sent ✓").replace("Bridge", "sent ✓") : label}
                    </button>
                  );
                })()}
              </>
            )}
          </div>
        </aside>
      </div>
    </div>
  );
}
