/**
 * Mock data for the Operations · Returns sub-page.
 *
 * Each return has refund + delivery + waste costs (USD). True cost is the
 * sum. Recovery describes how much of the returned goods comes back as
 * sellable stock (restock / partial / lost). Damaged-in-transit returns
 * carry a `flag` — a churn signal that routes to Customers.
 */

export type ReturnRecovery = "restock" | "partial" | "lost";
export type ReturnStatus = "pending" | "approved" | "resolved";

export interface ReturnRaw {
  id: string;
  order: string;
  customer: string;
  reason: string;
  /** Damaged-in-transit flag — churn risk signal */
  flag: boolean;
  /** USD refund issued */
  refund: number;
  /** USD return shipping */
  delivery: number;
  /** USD written off (damaged, labor) */
  waste: number;
  recovery: ReturnRecovery;
  status: ReturnStatus;
  date: string;
  item: string;
}

export interface ReturnRow extends ReturnRaw {
  idx: number;
  trueCost: number;
  statusSort: number;
  recSort: number;
}

